protected UnivariatePointValuePair doOptimize() {
    final boolean isMinim = getGoalType() == GoalType.MINIMIZE;
    final double lo = getMin();
    final double mid = getStartValue();
    final double hi = getMax();

    // Optional additional convergence criteria.
    final ConvergenceChecker<UnivariatePointValuePair> checker
        = getConvergenceChecker();

    double a, b;
    if (lo < hi) {
        a = lo;
        b = hi;
    } else {
        a = hi;
        b = lo;
    }

    double x = mid;
    double fx = computeObjectiveValue(x);
    if (!isMinim) {
        fx = -fx; // Invert objective value for maximization
    }

    double v = x, w = x, fv = fx, fw = fx;
    double d = 0, e = 0;

    UnivariatePointValuePair previous = null;
    UnivariatePointValuePair current = new UnivariatePointValuePair(x, isMinim ? fx : -fx);

    int iter = 0;
    while (true) {
        final double m = 0.5 * (a + b);
        final double tol1 = relativeThreshold * FastMath.abs(x) + absoluteThreshold;
        final double tol2 = 2 * tol1;

        // Stopping criterion
        if (FastMath.abs(x - m) <= tol2 - 0.5 * (b - a)) {
            return current; // Exit if within stopping criteria
        }

        double p = 0, q = 0, r = 0, u = 0;

        if (FastMath.abs(e) > tol1) { // Fit parabola
            r = (x - w) * (fx - fv);
            q = (x - v) * (fx - fw);
            p = (x - v) * q - (x - w) * r;
            q = 2 * (q - r);
            if (q > 0) p = -p; else q = -q; // Change the sign of p or q

            r = e;
            e = d;

            if (p > q * (a - x) && p < q * (b - x) && FastMath.abs(p) < FastMath.abs(0.5 * q * r)) {
                // Parabolic interpolation step
                d = p / q;
                u = x + d;

                // Ensure u is not too close to a or b
                if (u - a < tol2 || b - u < tol2) {
                    d = (x < m) ? tol1 : -tol1; // Step in direction of the interval center
                }
            } else {
                // Golden section step
                e = (x < m) ? b - x : a - x;
                d = GOLDEN_SECTION * e;
            }
        } else {
            // Golden section step
            e = (x < m) ? b - x : a - x;
            d = GOLDEN_SECTION * e;
        }

        // Ensure step is at least "tol1"
        if (FastMath.abs(d) < tol1) {
            u = (d >= 0) ? x + tol1 : x - tol1;
        } else {
            u = x + d;
        }

        double fu = computeObjectiveValue(u);
        if (!isMinim) {
            fu = -fu; // Invert for maximization
        }

        // User-defined convergence checker
        previous = current;
        current = new UnivariatePointValuePair(u, isMinim ? fu : -fu);

        if (checker != null && checker.converged(iter, previous, current)) {
            return current; // Convergence met
        }

        // Update interval a, b, v, w, and x
        if (fu <= fx) {
            if (u < x) {
                b = x; // Update upper bound
            } else {
                a = x; // Update lower bound
            }
            v = w; 
            fv = fw;
            w = x; 
            fw = fx;
            x = u; 
            fx = fu;
        } else {
            if (u < x) {
                a = u; // Update lower bound
